    # Constrain value to the inclusive [low, high] range.
    ...

exercises.solution_code:
def clamp(value, low, high):
    # Inclusive bounds: only push when strictly outside the range.
    if value < low:
        return low
    if value > high:
        return high
    return value

tests.content:
import pytest

from solution import clamp


# Stacked parametrize: pytest runs the cartesian product of both decorators.
# 3 bounds x 4 values = 12 generated cases, each with a readable id.
@pytest.mark.parametrize(
    "low, high",
    [
        pytest.param(0, 10, id="0..10"),
        pytest.param(-5, 5, id="-5..5"),
        pytest.param(100, 200, id="100..200"),
    ],
)
@pytest.mark.parametrize(
    "value",
    [
        pytest.param(-1000, id="far-below"),
        pytest.param(1000, id="far-above"),
        pytest.param(0, id="zero"),
        pytest.param(7, id="seven"),
    ],
)
def test_result_stays_within_bounds(value, low, high):
    result = clamp(value, low, high)
    assert low <= result <= high


def test_value_inside_range_is_unchanged():
    assert clamp(5, 0, 10) == 5


@pytest.mark.parametrize(
    "value, low, high, expected",
    [
        pytest.param(15, 0, 10, 10, id="above-clamps-to-high"),
        pytest.param(-3, 0, 10, 0, id="below-clamps-to-low"),
        pytest.param(0, 0, 10, 0, id="equal-to-low-kept"),
        pytest.param(10, 0, 10, 10, id="equal-to-high-kept"),
    ],
)
def test_boundary_behaviour(value, low, high, expected):
    # Tricky: boundaries are INCLUSIVE; value == low or == high must be kept,
    # not pushed. A strict < / > mistake breaks the equal-* cases.
    assert clamp(value, low, high) == expected
